'use client';

import { AlertTriangleIcon, DatabaseIcon } from 'lucide-react';
import Link from 'next/link';
import type { JSX } from 'react';
import type { LabeledOptionWithDescriptionDto } from '@/shared/contracts/base';
import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseType,
  MongoSource,
} from '@/shared/contracts/database';
import { AdminDatabaseBreadcrumbs } from '@/shared/ui/admin.public';
import { Alert, Badge, Button } from '@/shared/ui/primitives.public';
import { ListPanel } from '@/shared/ui/navigation-and-layout.public';
import { SimpleSettingsList } from '@/shared/ui/templates.public';
import {
  DatabaseOperationsTabs,
  type DatabaseOperationsTab,
} from './DatabaseOperationsTabs';
import { DatabaseProvider, useDatabaseConfig, useDatabaseData } from '../context/DatabaseContext';
import {
  buildManagedMongoCrudHref,
  ManagedMongoScopePanel,
} from './crud/ManagedMongoScopePanel';

const DATABASE_OPTIONS: Array<LabeledOptionWithDescriptionDto<DatabaseType>> = [
  {
    value: 'mongodb',
    label: 'MongoDB',
    description: 'Use the command console for MongoDB-backed operations.',
  },
];

const MANAGED_DATABASE_OPTIONS: Array<{
  application: DatabaseEngineManagedMongoApplication;
  label: string;
}> = [
  { application: 'geminitestapp', label: 'GeminiTest App' },
  { application: 'studiq', label: 'StudiQ' },
  { application: 'cms-builder', label: 'CMS Builder' },
  { application: 'products', label: 'Ecommerce' },
];

const MANAGED_SOURCE_OPTIONS: Array<{
  source: MongoSource;
  label: string;
}> = [
  { source: 'local', label: 'Local' },
  { source: 'cloud', label: 'Cloud' },
];

function DatabaseOperationsHeader({
  dbTypeLabel,
  tablesCount,
  activeApplication,
  activeSource,
}: {
  dbTypeLabel: string;
  tablesCount: number;
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  return (
    <div className='space-y-3'>
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <div className='space-y-1'>
          <h2 className='text-2xl font-bold tracking-tight text-white'>Operations Console</h2>
          <AdminDatabaseBreadcrumbs current='Operations' />
        </div>
        <div className='flex flex-wrap items-center gap-2'>
          <Badge variant='active' className='gap-1.5'>
            <DatabaseIcon className='size-3.5' />
            {dbTypeLabel}
          </Badge>
          <Badge variant='outline' className='border-white/10 text-gray-300'>
            {tablesCount.toLocaleString()} table{tablesCount === 1 ? '' : 's'}
          </Badge>
          <Badge variant='outline' className='border-white/10 text-gray-300'>
            {activeApplication} / {activeSource}
          </Badge>
        </div>
      </div>
    </div>
  );
}

function DatabaseOperationsFilters({
  dbType,
  setDbType,
  activeApplication,
  activeSource,
  activeSourceOptions,
  managedApplications,
}: {
  dbType: DatabaseType;
  setDbType: (dbType: DatabaseType) => void;
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
  activeSourceOptions: Array<{ source: MongoSource; label: string }>;
  managedApplications: Array<{ application: DatabaseEngineManagedMongoApplication; label: string }>;
}): JSX.Element {
  return (
    <div className='space-y-3'>
      <DatabaseTypeSettings
        dbType={dbType}
        setDbType={setDbType}
        activeApplication={activeApplication}
        activeSource={activeSource}
      />
      <DatabaseSourceButtons
        activeSource={activeSource}
        activeSourceOptions={activeSourceOptions}
        activeApplication={activeApplication}
      />
      <DatabaseApplicationsButtons
        managedApplications={managedApplications}
        activeApplication={activeApplication}
        activeSource={activeSource}
      />
    </div>
  );
}

function DatabaseTypeSettings({
  dbType,
  setDbType,
  activeApplication,
  activeSource,
}: {
  dbType: DatabaseType;
  setDbType: (dbType: DatabaseType) => void;
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  return (
    <>
      <SimpleSettingsList
        items={DATABASE_OPTIONS.map((option) => ({
          id: option.value,
          title: option.label,
          description: option.description,
          icon: (
            <div className='rounded-md border border-emerald-400/40 bg-emerald-500/20 p-2'>
              <DatabaseIcon className='size-4 text-emerald-200' />
            </div>
          ),
          original: option,
        }))}
        selectedId={dbType}
        onSelect={(item) => setDbType(item.original.value)}
        columns={2}
        padding='md'
      />
      <ManagedMongoScopePanel activeApplication={activeApplication} activeSource={activeSource} />
    </>
  );
}

function DatabaseSourceButtons({
  activeSource,
  activeSourceOptions,
  activeApplication,
}: {
  activeSource: MongoSource;
  activeSourceOptions: Array<{ source: MongoSource; label: string }>;
  activeApplication: DatabaseEngineManagedMongoApplication;
}): JSX.Element {
  return (
    <div className='flex flex-wrap items-center gap-2'>
      <span className='text-xs text-gray-400'>Source</span>
      {activeSourceOptions.map((option) => (
        <Button
          key={option.source}
          asChild
          variant={activeSource === option.source ? 'secondary' : 'outline'}
          size='xs'
        >
          <Link href={buildManagedMongoCrudHref(activeApplication, option.source)}>
            {option.label}
          </Link>
        </Button>
      ))}
    </div>
  );
}

function DatabaseApplicationsButtons({
  managedApplications,
  activeApplication,
  activeSource,
}: {
  managedApplications: Array<{ application: DatabaseEngineManagedMongoApplication; label: string }>;
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  return (
    <div className='flex flex-wrap gap-2'>
      {managedApplications.map((option) => (
        <Button
          key={option.application}
          asChild
          variant={activeApplication === option.application ? 'secondary' : 'outline'}
          size='xs'
        >
          <Link href={buildManagedMongoCrudHref(option.application, activeSource)}>
            {option.label}
          </Link>
        </Button>
      ))}
    </div>
  );
}

function DatabaseOperationsPanelContent({
  activeApplication,
  activeSource,
  defaultTab,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
  defaultTab: DatabaseOperationsTab;
}): JSX.Element {
  const { dbType, setDbType } = useDatabaseConfig();
  const { tableDetails } = useDatabaseData();

  return (
    <ListPanel
      header={
        <DatabaseOperationsHeader
          dbTypeLabel={DATABASE_OPTIONS[0].label}
          tablesCount={tableDetails.length}
          activeApplication={activeApplication}
          activeSource={activeSource}
        />
      }
      alerts={
        process.env['NODE_ENV'] === 'production' ? (
          <Alert variant='warning' className='flex items-center gap-2'>
            <AlertTriangleIcon className='size-4' />
            Database operations are disabled in production environments.
          </Alert>
        ) : null
      }
      filters={
        <DatabaseOperationsFilters
          dbType={dbType}
          setDbType={setDbType}
          activeApplication={activeApplication}
          activeSource={activeSource}
          activeSourceOptions={MANAGED_SOURCE_OPTIONS}
          managedApplications={MANAGED_DATABASE_OPTIONS}
        />
      }
    >
      <DatabaseOperationsTabs defaultTab={defaultTab} />
    </ListPanel>
  );
}

export function DatabaseOperationsPanel({
  defaultTab = 'sql',
  application,
  source,
}: {
  defaultTab?: DatabaseOperationsTab;
  application?: DatabaseEngineManagedMongoApplication | undefined;
  source?: MongoSource | undefined;
}): JSX.Element {
  const activeApplication = application ?? 'geminitestapp';
  const activeSource = source ?? 'local';

  return (
    <DatabaseProvider application={activeApplication} source={activeSource}>
      <DatabaseOperationsPanelContent
        activeApplication={activeApplication}
        activeSource={activeSource}
        defaultTab={defaultTab}
      />
    </DatabaseProvider>
  );
}

'use client';

import { DatabaseIcon, DownloadIcon } from 'lucide-react';
import Link from 'next/link';
import type { JSX } from 'react';

import type { DatabaseEngineManagedMongoApplication, DatabaseInfo } from '@/shared/contracts/database';
import { Badge, Button } from '@/shared/ui/primitives.public';

import { buildManagedMongoCrudHref } from '../crud/ManagedMongoScopePanel';
import { useDatabaseBackupsStateContext } from '../../context/DatabaseBackupsContext';
import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';

type BackupApplicationSummaryItem = {
  application: DatabaseEngineManagedMongoApplication;
  label: string;
  folder: string;
  count: number;
  totalSizeBytes: number;
  latestBackup: DatabaseInfo | null;
};

const MANAGED_APPLICATIONS: Array<{
  application: DatabaseEngineManagedMongoApplication;
  label: string;
}> = [
  { application: 'geminitestapp', label: 'GeminiTest App' },
  { application: 'studiq', label: 'StudiQ' },
  { application: 'cms-builder', label: 'CMS Builder' },
  { application: 'products', label: 'Ecommerce' },
];

const APPLICATION_SET = new Set(MANAGED_APPLICATIONS.map((item) => item.application));

const getBackupApplication = (
  backupName: string
): DatabaseEngineManagedMongoApplication => {
  const [firstSegment] = backupName.split('/');
  return APPLICATION_SET.has(firstSegment as DatabaseEngineManagedMongoApplication)
    ? (firstSegment as DatabaseEngineManagedMongoApplication)
    : 'geminitestapp';
};

const getBackupTimestamp = (backup: DatabaseInfo): number => {
  const timestamp = Date.parse(backup.lastModifiedAt ?? backup.createdAt);
  return Number.isFinite(timestamp) ? timestamp : 0;
};

const formatTimestamp = (value: string | null | undefined): string => {
  if (value === null || value === undefined || value === '') {
    return 'Never';
  }
  const timestamp = Date.parse(value);
  return Number.isFinite(timestamp) ? new Date(timestamp).toLocaleString() : 'Never';
};

const formatBytes = (bytes: number): string => {
  if (bytes < 1024) {
    return `${bytes} B`;
  }
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;

  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }

  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getBackupDisabledTitle = (
  isBackupDisabled: boolean,
  isProd: boolean
): string | undefined => {
  if (!isBackupDisabled) {
    return undefined;
  }
  return isProd ? 'Disabled in production' : 'Disabled by Database Engine operation controls';
};

const getLatestBackupTimestamp = (latestBackup: DatabaseInfo | null): string => {
  if (latestBackup === null) {
    return 'Never';
  }

  return formatTimestamp(latestBackup.lastModifiedAt ?? latestBackup.createdAt);
};

const getLatestBackupName = (latestBackup: DatabaseInfo | null): string => {
  if (latestBackup === null) {
    return 'No backup yet';
  }

  return latestBackup.name;
};

export const buildBackupApplicationSummaries = (
  backups: DatabaseInfo[]
): BackupApplicationSummaryItem[] =>
  MANAGED_APPLICATIONS.map(({ application, label }) => {
    const applicationBackups = backups.filter(
      (backup) => getBackupApplication(backup.name) === application
    );
    const latestBackup =
      applicationBackups.length === 0
        ? null
        : [...applicationBackups].sort(
            (left, right) => getBackupTimestamp(right) - getBackupTimestamp(left)
          )[0] ?? null;

    return {
      application,
      label,
      folder: `${application}/`,
      count: applicationBackups.length,
      totalSizeBytes: applicationBackups.reduce((sum, backup) => sum + backup.size, 0),
      latestBackup,
    };
  });

type BackupApplicationSummaryCardProps = {
  summary: BackupApplicationSummaryItem;
  isBackupDisabled: boolean;
  backupTitle: string | undefined;
  onBackup: (application: DatabaseEngineManagedMongoApplication) => void;
};

function SummaryCardHeader({
  label,
  folder,
  count,
}: {
  label: string;
  folder: string;
  count: number;
}): JSX.Element {
  const badgeVariant = count > 0 ? 'active' : 'outline';
  return (
    <div className='flex items-start justify-between gap-3'>
      <div className='min-w-0 space-y-1'>
        <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
          <DatabaseIcon className='size-4 shrink-0 text-emerald-200' />
          <span className='truncate'>{label}</span>
        </h3>
        <p className='font-mono text-xs text-gray-400'>{folder}</p>
      </div>
      <Badge variant={badgeVariant} className='text-xs'>
        {count.toLocaleString()}
      </Badge>
    </div>
  );
}

function SummaryCardStats({
  totalSizeBytes,
  latestTimestamp,
  latestBackupName,
  latestBackupTitle,
}: {
  totalSizeBytes: number;
  latestTimestamp: string;
  latestBackupName: string;
  latestBackupTitle: string;
}): JSX.Element {
  return (
    <div className='space-y-1 text-xs text-gray-300'>
      <p>Total backup size: {formatBytes(totalSizeBytes)}</p>
      <p>Latest: {latestTimestamp}</p>
      <p className='truncate font-mono text-gray-500' title={latestBackupTitle}>
        {latestBackupName}
      </p>
    </div>
  );
}

function SummaryCardActions({
  isBackupDisabled,
  backupTitle,
  application,
  onBackup,
}: {
  isBackupDisabled: boolean;
  backupTitle: string | undefined;
  application: DatabaseEngineManagedMongoApplication;
  onBackup: (application: DatabaseEngineManagedMongoApplication) => void;
}): JSX.Element {
  return (
    <div className='flex flex-wrap gap-2'>
      <Button
        type='button'
        variant='outline'
        size='xs'
        disabled={isBackupDisabled}
        title={backupTitle}
        onClick={() => {
          onBackup(application);
        }}
      >
        <DownloadIcon className='size-3.5' />
        Backup
      </Button>
      <Button asChild variant='outline' size='xs'>
        <Link href={buildManagedMongoCrudHref(application, 'local')}>Local Tables</Link>
      </Button>
      <Button asChild variant='outline' size='xs'>
        <Link href={buildManagedMongoCrudHref(application, 'cloud')}>Cloud Tables</Link>
      </Button>
    </div>
  );
}

function BackupApplicationSummaryCard({
  summary,
  isBackupDisabled,
  backupTitle,
  onBackup,
}: BackupApplicationSummaryCardProps): JSX.Element {
  const latestTimestamp = getLatestBackupTimestamp(summary.latestBackup);
  const latestBackupName = getLatestBackupName(summary.latestBackup);

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-card/30 p-3'>
      <SummaryCardHeader label={summary.label} folder={summary.folder} count={summary.count} />
      <SummaryCardStats
        totalSizeBytes={summary.totalSizeBytes}
        latestTimestamp={latestTimestamp}
        latestBackupName={latestBackupName}
        latestBackupTitle={latestBackupName}
      />
      <SummaryCardActions
        isBackupDisabled={isBackupDisabled}
        backupTitle={backupTitle}
        application={summary.application}
        onBackup={onBackup}
      />
    </div>
  );
}

export function BackupApplicationSummary(): JSX.Element {
  const { data, backupRunNowAllowed, isProd } = useDatabaseBackupsStateContext();
  const { backupManagedMongo } = useDatabaseEngineActionsContext();
  const { isBackingUpManagedMongo } = useDatabaseEngineStateContext();
  const summaries = buildBackupApplicationSummaries(data);
  const isBackupDisabled = isProd || !backupRunNowAllowed || isBackingUpManagedMongo;
  const backupTitle = getBackupDisabledTitle(isBackupDisabled, isProd);

  const handleBackup = (application: DatabaseEngineManagedMongoApplication): void => {
    void backupManagedMongo(application);
  };

  return (
    <div className='grid gap-3 md:grid-cols-2 xl:grid-cols-4'>
      {summaries.map((summary) => (
        <BackupApplicationSummaryCard
          key={summary.application}
          summary={summary}
          isBackupDisabled={isBackupDisabled}
          backupTitle={backupTitle}
          onBackup={handleBackup}
        />
      ))}
    </div>
  );
}

'use client';

import Link from 'next/link';
import { CloudUploadIcon, DatabaseIcon, DownloadIcon, PencilIcon, RefreshCwIcon } from 'lucide-react';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineManagedMongoCollectionStats,
  DatabaseEngineManagedMongoDatabase,
  DatabaseEngineManagedMongoDatabasesResponse,
  DatabaseEngineManagedMongoEndpoint,
  DatabaseEngineMongoPendingSyncRequest,
  MongoSource,
} from '@/shared/contracts/database';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { Button, Card } from '@/shared/ui/primitives.public';
import { buildManagedMongoCrudHref } from '../crud/ManagedMongoScopePanel';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

export const isPendingSyncTarget = (
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null,
  direction: 'cloud_to_local' | 'local_to_cloud',
  application: DatabaseEngineManagedMongoApplicationTarget
): boolean =>
  pendingSync !== null &&
  pendingSync.direction === direction &&
  pendingSync.application === application;

export const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatus = (
  endpoint: DatabaseEngineManagedMongoEndpoint
): { status: string; variant: 'active' | 'error' | 'pending' } => {
  if (!endpoint.configured) return { status: 'Not configured', variant: 'pending' };
  if (endpoint.reachable === true) return { status: 'Reachable', variant: 'active' };
  if (endpoint.reachable === false) return { status: 'Unreachable', variant: 'error' };
  return { status: 'Unknown', variant: 'pending' };
};

export function CollectionSizeList({
  collections,
}: {
  collections: DatabaseEngineManagedMongoCollectionStats[];
}): JSX.Element {
  if (collections.length === 0) {
    return <p className='text-xs text-gray-400'>No collection stats available.</p>;
  }

  return (
    <div className='max-h-52 overflow-auto rounded-md border border-white/10'>
      <table className='w-full text-left text-[11px]'>
        <thead className='sticky top-0 bg-gray-950 text-gray-400'>
          <tr>
            <th className='px-2 py-1.5 font-medium'>Collection</th>
            <th className='px-2 py-1.5 text-right font-medium'>Docs</th>
            <th className='px-2 py-1.5 text-right font-medium'>Size</th>
          </tr>
        </thead>
        <tbody>
          {collections.map((collection) => (
            <tr key={collection.name} className='border-t border-white/10 text-gray-300'>
              <td className='max-w-40 truncate px-2 py-1.5 font-mono' title={collection.name}>
                {collection.name}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {collection.documentCount?.toLocaleString() ?? 'n/a'}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {formatBytes(collection.totalSizeBytes)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export function EndpointPanel({
  endpoint,
}: {
  endpoint: DatabaseEngineManagedMongoEndpoint;
}): JSX.Element {
  const status = getEndpointStatus(endpoint);

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-black/20 p-3'>
      <div className='flex items-start justify-between gap-2'>
        <div className='space-y-1'>
          <h4 className='text-xs font-semibold uppercase text-gray-300'>
            {SOURCE_LABELS[endpoint.source]}
          </h4>
          <p className='text-xs text-gray-400'>{endpoint.dbName ?? 'No database selected'}</p>
        </div>
        <StatusBadge status={status.status} variant={status.variant} size='sm' />
      </div>

      <div className='space-y-1 text-xs text-gray-300'>
        <p className='truncate' title={endpoint.maskedUri ?? ''}>
          {endpoint.maskedUri ?? 'No URI configured'}
        </p>
        <p>Database size: {formatBytes(endpoint.databaseSizeBytes)}</p>
        <p>Collections: {endpoint.collectionCount.toLocaleString()}</p>
        <p>Collection storage: {formatBytes(endpoint.collectionsSizeBytes)}</p>
        {endpoint.healthError !== null && endpoint.healthError !== '' ? <p className='text-rose-200'>{endpoint.healthError}</p> : null}
      </div>

      <CollectionSizeList collections={endpoint.collections} />
    </div>
  );
}

export function ManagedDatabaseCardHeader({
  database,
}: {
  database: DatabaseEngineManagedMongoDatabase;
}): JSX.Element {
  return (
    <div className='space-y-1'>
      <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
        <DatabaseIcon className='size-4 text-emerald-200' />
        {database.label}
      </h3>
      {database.syncIssue !== null && database.syncIssue !== '' && (
        <p className='text-xs leading-relaxed text-amber-100'>{database.syncIssue}</p>
      )}
    </div>
  );
}

export function ManagedDatabaseCardActions({
  database,
  isBackupDisabled,
  isPushDisabled,
  isPullDisabled,
  isPushing,
  isPulling,
  backupManagedMongo,
  syncManagedMongo,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  isBackupDisabled: boolean;
  isPushDisabled: boolean;
  isPullDisabled: boolean;
  isPushing: boolean;
  isPulling: boolean;
  backupManagedMongo: (application: DatabaseEngineManagedMongoApplicationTarget) => Promise<void> | void;
  syncManagedMongo: (
    direction: 'local_to_cloud' | 'cloud_to_local',
    application: DatabaseEngineManagedMongoApplicationTarget
  ) => Promise<void> | void;
}): JSX.Element {
  return (
    <div className='flex flex-wrap gap-2'>
      <Button asChild type='button' variant='outline' size='sm'>
        <Link href={buildManagedMongoCrudHref(database.application, 'local')}>
          <PencilIcon className='size-3.5' />
          Local Tables
        </Link>
      </Button>
      <Button asChild type='button' variant='outline' size='sm'>
        <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>
          <PencilIcon className='size-3.5' />
          Cloud Tables
        </Link>
      </Button>
      <Button
        type='button'
        variant='outline'
        size='sm'
        disabled={isBackupDisabled}
        onClick={() => {
          void backupManagedMongo(database.application);
        }}
      >
        <DownloadIcon className='size-3.5' />
        Backup
      </Button>
      <Button
        type='button'
        size='sm'
        disabled={isPushDisabled}
        loading={isPushing}
        loadingText='Pushing...'
        onClick={() => {
          void syncManagedMongo('local_to_cloud', database.application);
        }}
      >
        <CloudUploadIcon className='size-3.5' />
        Push
      </Button>
      <Button
        type='button'
        variant='outline'
        size='sm'
        disabled={isPullDisabled}
        loading={isPulling}
        loadingText='Pulling...'
        onClick={() => {
          void syncManagedMongo('cloud_to_local', database.application);
        }}
      >
        <RefreshCwIcon className='size-3.5' />
        Pull
      </Button>
    </div>
  );
}

export function ManagedDatabaseCard({
  database,
  backupDisabled,
  syncDisabled,
  pendingSync,
  backupManagedMongo,
  syncManagedMongo,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  backupDisabled: boolean;
  syncDisabled: boolean;
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null;
  backupManagedMongo: (application: DatabaseEngineManagedMongoApplicationTarget) => Promise<void> | void;
  syncManagedMongo: (
    direction: 'local_to_cloud' | 'cloud_to_local',
    application: DatabaseEngineManagedMongoApplicationTarget
  ) => Promise<void> | void;
}): JSX.Element {
  const isPushing = isPendingSyncTarget(pendingSync, 'local_to_cloud', database.application);
  const isPulling = isPendingSyncTarget(pendingSync, 'cloud_to_local', database.application);

  return (
    <Card variant='subtle' padding='md' className='space-y-4 border-white/10'>
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <ManagedDatabaseCardHeader database={database} />
        <ManagedDatabaseCardActions
          database={database}
          isBackupDisabled={backupDisabled || !database.canBackupLocal}
          isPushDisabled={syncDisabled || !database.canPushToCloud}
          isPullDisabled={syncDisabled || !database.canPullFromCloud}
          isPushing={isPushing}
          isPulling={isPulling}
          backupManagedMongo={backupManagedMongo}
          syncManagedMongo={syncManagedMongo}
        />
      </div>

      <div className='grid gap-4 xl:grid-cols-2'>
        <EndpointPanel endpoint={database.local} />
        <EndpointPanel endpoint={database.cloud} />
