const resolvePreviewTarget = (
  previewMode: 'backup' | 'current',
  backupName: string | undefined
): { mongoUri: string; sourceDbName: string } => {
  if (previewMode === 'backup' && backupName) {
    const application = getMongoBackupApplication(backupName);
    if (application === 'studiq') {
      return {
        mongoUri: getStudiqMongoConnectionUrl(),
        sourceDbName: getStudiqMongoDatabaseName(),
      };
    }
    if (application === 'cms-builder') {
      return {
        mongoUri: getCmsBuilderMongoConnectionUrl(),
        sourceDbName: getCmsBuilderMongoDatabaseName(),
      };
    }
    if (application === 'products') {
      return {
        mongoUri: getEcommerceMongoConnectionUrl(),
        sourceDbName: getEcommerceMongoDatabaseName(),
      };
    }
  }

  return {
    mongoUri: getMongoConnectionUrl(),
    sourceDbName: getMongoDatabaseName(),
  };
};

const getFieldType = (value: unknown): string => {
  if (value === null) return 'null';
  if (Array.isArray(value)) return 'array';
  if (value instanceof Date) return 'date';
  if (
    typeof value === 'object' &&
    value !== null &&
    (value as { constructor?: { name?: string } }).constructor?.name === 'ObjectId'
  ) {
    return 'ObjectId';
  }
  return typeof value;
};

const getNumber = (value: unknown): number | null => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return null;
  return Math.max(0, value);
};

const sumNullableNumbers = (...values: Array<number | null>): number | null => {
  const finiteValues = values.filter((value): value is number => value !== null);
  if (finiteValues.length === 0) return null;
  return finiteValues.reduce((sum, value) => sum + value, 0);
};

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getDatabaseSizeFormatted = async (db: Db): Promise<string> => {
  try {
    const stats = (await db.command({ dbStats: 1, scale: 1 })) as Record<string, unknown>;
    const storageSizeBytes = getNumber(stats['storageSize']);
    const indexSizeBytes = getNumber(stats['indexSize']);
    const databaseSizeBytes =
      getNumber(stats['totalSize']) ?? sumNullableNumbers(storageSizeBytes, indexSizeBytes);
    return formatBytes(databaseSizeBytes);
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'database-stats',
    });
    return 'n/a';
  }
};

const getCollectionSizeFormatted = async (
  db: Db,
  collectionName: string
): Promise<string> => {
  try {
    const stats = (await db.command({
      collStats: collectionName,
      scale: 1,
    })) as Record<string, unknown>;
    const storageSizeBytes = getNumber(stats['storageSize']);
    const indexSizeBytes = getNumber(stats['totalIndexSize']);
    const collectionSizeBytes =
      getNumber(stats['totalSize']) ?? sumNullableNumbers(storageSizeBytes, indexSizeBytes);
    return formatBytes(collectionSizeBytes);
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'collection-stats',
      collectionName,
    });
    return 'n/a';
  }
};

const buildIndexDefinition = (index: Record<string, unknown>): string | undefined => {
  const key = index['key'];
  if (typeof key !== 'object' || key === null || Array.isArray(key)) return undefined;

  return Object.entries(key)
    .map(([column, direction]) => `${column}: ${String(direction)}`)
    .join(', ');
};

const getCollectionIndexes = async (
  collection: Collection
): Promise<DatabaseIndexInfo[]> => {
  try {
    const indexes = (await collection.indexes()) as Array<Record<string, unknown>>;
    return indexes
      .map((index) => {
        const key = index['key'];
        const columns =
          typeof key === 'object' && key !== null && !Array.isArray(key)
            ? Object.keys(key)
            : [];
        const fallbackName = columns.length > 0 ? columns.join('_') : 'index';
        const name = typeof index['name'] === 'string' ? index['name'] : fallbackName;

        return {
          name,
          columns,
          isUnique: index['unique'] === true,
          definition: buildIndexDefinition(index),
        };
      })
      .sort((a, b) => {
        if (a.name === '_id_') return -1;
        if (b.name === '_id_') return 1;
        return a.name.localeCompare(b.name);
      });
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'collection-indexes',
      collectionName: collection.collectionName,
    });
    return [];
  }
};

const buildTableDetail = (
  collectionName: string,
  sample: Record<string, unknown>[],
  indexes: DatabaseIndexInfo[],
  rowEstimate: number,
  sizeFormatted: string
): DatabaseTableDetail => {
  const fieldTypes = new Map<string, Set<string>>();
  for (const doc of sample) {
    for (const [key, value] of Object.entries(doc)) {
      if (!fieldTypes.has(key)) fieldTypes.set(key, new Set<string>());
      fieldTypes.get(key)?.add(getFieldType(value));
    }
  }

  const fields: DatabaseColumnInfo[] = [...fieldTypes.entries()]
    .map(([name, types]) => ({
      name,
      type: [...types].join(' | ') || 'unknown',
      nullable: types.has('null'),
      defaultValue: null,
      isPrimaryKey: name === '_id',
      isForeignKey: false,
    }))
    .sort((a, b) => {
      if (a.name === '_id') return -1;
      if (b.name === '_id') return 1;
      return a.name.localeCompare(b.name);
    });

  return {
    name: collectionName,
    columns: fields,
    indexes,
    foreignKeys: [],
    rowEstimate,
    sizeFormatted,
  };
};

export async function postDatabasesPreviewHandler(
  req: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  const parsed = await parseObjectJsonBody(req, {
    logPrefix: 'database-engine-web.databases.preview',
  });
  if (!parsed.ok) {
    return parsed.response;
  }

  const body = z
    .object({
      backupName: z.string().optional(),
      mode: z.enum(['backup', 'current']).optional(),
      type: z.enum(['mongodb']).optional(),
      page: z.number().optional(),
      pageSize: z.number().optional(),
      application: databaseEngineManagedMongoApplicationSchema.optional(),
      source: mongoSourceSchema.optional(),
    })
    .parse(parsed.data);

  const previewMode = body.mode === 'current' ? 'current' : 'backup';
  const previewType = body.type ?? 'mongodb';
  const backupName = body.backupName;

  if (previewType !== 'mongodb') {
    throw badRequestError('Only MongoDB previews are supported.');
  }
  if (previewMode === 'backup' && !backupName) {
    throw badRequestError('Backup name is required');
  }
  if (previewMode === 'backup') {
    assertValidMongoBackupName(backupName ?? '');
    await ensureMongoBackupsDir();
  }

  const requestedApplication = body.application;
  const requestedSource = (body.source ?? 'local');
  const usesManagedCurrent = previewMode === 'current' && requestedApplication !== undefined;
  const target = usesManagedCurrent ? null : resolvePreviewTarget(previewMode, backupName);
  const mongoUri = target?.mongoUri ?? '';
  const sourceDbName = target?.sourceDbName ?? '';
  const previewDb = previewMode === 'backup' ? `stardb_preview_${Date.now()}` : sourceDbName;
  const page = Math.max(1, Number.isFinite(body.page) ? Number(body.page) : 1);
  const pageSize = Math.min(
    200,
    Math.max(1, Number.isFinite(body.pageSize) ? Number(body.pageSize) : 20)
  );
  const offset = (page - 1) * pageSize;

  if (previewMode === 'backup') {
    const backupPath = await resolveMongoBackupPath(backupName ?? '');
    try {
      await mongoExecFileAsync(getMongoRestoreCommand(), [
        '--uri',
        mongoUri,
        `--archive=${backupPath}`,
        '--gzip',
        '--nsFrom',
        `${sourceDbName}.*`,
        '--nsTo',
        `${previewDb}.*`,
        '--drop',
      ]);
    } catch (error) {
      void ErrorSystem.captureException(error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      throw internalError(`Failed to inspect backup: ${message}`);
    }
  }

  const managedMongo =
    usesManagedCurrent && requestedApplication
      ? await createManagedMongoClient(requestedApplication, requestedSource)
      : null;
  const mongoClient = managedMongo?.client ?? new MongoClient(mongoUri);
  if (managedMongo === null) {
    await mongoClient.connect();
  }
  const db = managedMongo?.db ?? mongoClient.db(previewDb);
  let collections: string[] = [];
  let tableRows: { name: string; rows: Record<string, unknown>[]; totalRows: number }[] = [];
  let tableStats: { name: string; rowEstimate: number; sizeFormatted: string }[] = [];
  let tableDetails: DatabaseTableDetail[] = [];
  let databaseSize = 'n/a';

  try {
    const [databaseSizeResult, collectionInfos] = await Promise.all([
      getDatabaseSizeFormatted(db),
      db.listCollections().toArray(),
    ]);
    databaseSize = databaseSizeResult;
    collections = collectionInfos
      .map((info: { name: string }) => info.name)
      .sort((a, b) => a.localeCompare(b));

    tableRows = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const totalRows = await collection.countDocuments();
        const rows = await collection.find({}).skip(offset).limit(pageSize).toArray();
        return { name: collectionName, rows: rows as Record<string, unknown>[], totalRows };
      })
    );

    tableStats = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const [estimate, sizeFormatted] = await Promise.all([
          collection.estimatedDocumentCount(),
          getCollectionSizeFormatted(db, collectionName),
        ]);
        return { name: collectionName, rowEstimate: estimate, sizeFormatted };
      })
    );
    tableDetails = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const [sample, indexes] = await Promise.all([
          collection.find({}).limit(10).toArray() as Promise<Record<string, unknown>[]>,
          getCollectionIndexes(collection),
        ]);
        const collectionStats = tableStats.find((table) => table.name === collectionName);
        return buildTableDetail(
          collectionName,
          sample,
          indexes,
          collectionStats?.rowEstimate ?? 0,
          collectionStats?.sizeFormatted ?? 'n/a'
        );
      })
    );
  } finally {
    if (previewMode === 'backup') {
      try {
        await db.dropDatabase();
      } catch (error) {
        void ErrorSystem.captureException(error);
        void ErrorSystem.captureException(error, {
          service: 'api/databases/preview',
          stage: 'cleanup-preview-db',
          previewDb,
        });
      }
    }
    await mongoClient.close();
  }

  return NextResponse.json({
    stats: {
      tables: tableStats,
      groups: collections.length > 0 ? { COLLECTION: collections } : {},
    },
    data: tableRows,
    tableDetails,
    databaseSize,
    page,
    pageSize,
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type { RedisOverview } from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { optionalIntegerQuerySchema } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { getRedisClient } from '@/shared/lib/redis';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


export const querySchema = z.object({
  limit: optionalIntegerQuerySchema(z.number().int().min(20).max(2000)),
  count: optionalIntegerQuerySchema(z.number().int().min(20).max(1000)),
});

const parseInfoValue = (info: string, key: string): string | null => {
  const row = info
    .split('\n')
    .map((line: string) => line.trim())
    .find((line: string) => line.startsWith(`${key}:`));
  if (!row) return null;
  return row.slice(key.length + 1) || null;
};

const getNamespace = (key: string): string => {
  const idx = key.indexOf(':');
  if (idx <= 0) return '(root)';
  return key.slice(0, idx);
};

export async function getHandler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const client = getRedisClient();
  if (!client) {
    const disabled: RedisOverview = {
      enabled: false,
      connected: false,
      urlConfigured: Boolean(process.env['REDIS_URL']),
      dbSize: 0,
      usedMemory: null,
      maxMemory: null,
      namespaces: [],
      sampleKeys: [],
      status: 'disabled',
      version: 'n/a',
      keysCount: 0,
      memoryUsed: '0',
      uptime: '0',
      clients: 0,
    };
    return NextResponse.json(disabled, {
      headers: { 'Cache-Control': 'no-store' },
    });
  }

  const limit = query.limit ?? 200;
  const count = query.count ?? 200;

  let connected: boolean;
  try {
    await client.ping();
    connected = true;
  } catch (error) {
    void ErrorSystem.captureException(error);
    connected = false;
  }

  const dbSize = connected ? await client.dbsize().catch(() => 0) : 0;
  const memoryInfo = connected ? await client.info('memory').catch(() => '') : '';
  const usedMemory = parseInfoValue(memoryInfo, 'used_memory_human');
  const maxMemory = parseInfoValue(memoryInfo, 'maxmemory_human');

  const keys: string[] = [];
  if (connected) {
    let cursor = '0';
    do {
      const response = await client.scan(cursor, 'COUNT', String(count));
      const batch = response[1] ?? [];
      keys.push(...batch);
      cursor = response[0] ?? '0';
      if (keys.length >= limit) break;
    } while (cursor !== '0');
  }

  const cappedKeys = keys.slice(0, limit);
  const namespaceMap = new Map<string, { keyCount: number; sampleKeys: string[] }>();
  cappedKeys.forEach((key: string) => {
    const namespace = getNamespace(key);
    const current = namespaceMap.get(namespace) ?? { keyCount: 0, sampleKeys: [] };
    current.keyCount += 1;
    if (current.sampleKeys.length < 5) {
      current.sampleKeys.push(key);
    }
    namespaceMap.set(namespace, current);
  });

  const namespaces = Array.from(namespaceMap.entries())
    .map(([namespace, stats]) => ({
      namespace,
      keyCount: stats.keyCount,
      sampleKeys: stats.sampleKeys,
    }))
    .sort((a, b) => b.keyCount - a.keyCount || a.namespace.localeCompare(b.namespace));

  const payload: RedisOverview = {
    enabled: true,
    connected,
    urlConfigured: Boolean(process.env['REDIS_URL']),
    dbSize,
    usedMemory,
    maxMemory,
    namespaces,
    sampleKeys: cappedKeys.slice(0, 25),
  };

  return NextResponse.json(payload, {
    headers: { 'Cache-Control': 'no-store' },
  });
}

import { promises as fs } from 'fs';
import path from 'path';

import { type NextRequest, NextResponse } from 'next/server';
import { MongoClient } from 'mongodb';
import { z } from 'zod';

import {
  ensureMongoBackupsDir,
  assertValidMongoBackupName,
  getMongoBackupApplication,
  getMongoConnectionUrl,
  getMongoDatabaseName,
  getMongoRestoreCommand,
  getCmsBuilderMongoConnectionUrl,
  getCmsBuilderMongoDatabaseName,
  getEcommerceMongoConnectionUrl,
  getEcommerceMongoDatabaseName,
  getStudiqMongoConnectionUrl,
  getStudiqMongoDatabaseName,
  mongoExecFileAsync,
  resolveMongoBackupPath,
} from '@/features/database/server';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, internalError } from '@/shared/errors/app-error';
import { parseObjectJsonBody } from '@/shared/lib/api/parse-json';
import { normalizeOptionalQueryString } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { assertDatabaseEngineOperationEnabled } from '@/shared/lib/db/services/database-engine-operation-guards';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


type ExecOutputishError = {
  stdout?: string;
  stderr?: string;
  cause?: {
    stdout?: string;
    stderr?: string;
  };
};

export const querySchema = z.object({
  type: z.preprocess(
    (value: unknown) => normalizeOptionalQueryString(value),
    z.enum(['mongodb']).optional()
  ),
});

const resolveRestoreTarget = (backupName: string): { mongoUri: string; databaseName: string } => {
  const application = getMongoBackupApplication(backupName);
  if (application === 'studiq') {
    return {
      mongoUri: getStudiqMongoConnectionUrl(),
      databaseName: getStudiqMongoDatabaseName(),
    };
  }

  if (application === 'cms-builder') {
    return {
      mongoUri: getCmsBuilderMongoConnectionUrl(),
      databaseName: getCmsBuilderMongoDatabaseName(),
    };
  }

  if (application === 'products') {
    return {
      mongoUri: getEcommerceMongoConnectionUrl(),
      databaseName: getEcommerceMongoDatabaseName(),
    };
  }

  return {
    mongoUri: getMongoConnectionUrl(),
    databaseName: getMongoDatabaseName(),
  };
};

export async function postDatabasesRestoreHandler(
  req: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  await assertDatabaseEngineOperationEnabled('allowManualBackupMaintenance');

  let stage = 'validate';

  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const type = query.type ?? 'mongodb';
  if (type !== 'mongodb') {
    throw badRequestError('Only MongoDB restores are supported.');
  }

  const parsed = await parseObjectJsonBody(req, {
    logPrefix: 'database-engine-web.databases.restore',
  });
  if (!parsed.ok) {
    return parsed.response;
  }

  const body = z
    .object({
      backupName: z.string(),
      truncateBeforeRestore: z.boolean().optional(),
    })
    .parse(parsed.data);

  const backupName = body.backupName;
  const truncateBeforeRestore = Boolean(body.truncateBeforeRestore);
  if (!backupName) {
    throw badRequestError('Backup name is required');
  }

  assertValidMongoBackupName(backupName);
  await ensureMongoBackupsDir();

  const backupPath = await resolveMongoBackupPath(backupName);
  const { mongoUri, databaseName } = resolveRestoreTarget(backupName);

  if (truncateBeforeRestore) {
    const mongoClient = new MongoClient(mongoUri);
    try {
      await mongoClient.connect();
      const db = mongoClient.db(databaseName);
      const collections = await db.listCollections().toArray();

      for (const collection of collections) {
        await db.collection(collection.name).drop();
      }
    } finally {
      await mongoClient.close();
    }
  }

  stage = 'mongorestore';
  const logPath = `${backupPath}.restore.log`;
  const command = getMongoRestoreCommand();
  const args = [
    '--uri',
    mongoUri,
    '--db',
    databaseName,
    `--archive=${backupPath}`,
    '--gzip',
    '--drop',
  ];
  const commandString = `${command} ${args.join(' ')}`;

  let stdout = '';
  let stderr = '';

  try {
    const result = await mongoExecFileAsync(command, args);
    stdout = result.stdout;
    stderr = result.stderr;
  } catch (error) {
    void ErrorSystem.captureException(error);
    const err = error as ExecOutputishError;
    stdout = err.stdout ?? err.cause?.stdout ?? '';
    stderr = err.stderr ?? err.cause?.stderr ?? '';

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
    await fs.writeFile(logPath, logContent);
    throw internalError('Failed to restore backup', {
      stage,
      backupName,
      log: logContent,
    });
  }

  const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
  await fs.writeFile(logPath, logContent);

  stage = 'log';
  const restoreLogPath = path.join(path.dirname(backupPath), 'restore-log.json');
  let logData: Record<string, { date: string; logFile: string }> = {};

  try {
    const logFile = await fs.readFile(restoreLogPath, 'utf-8');
    logData = JSON.parse(logFile) as Record<string, { date: string; logFile: string }>;
  } catch (error) {
    void ErrorSystem.captureException(error);
    const { ErrorSystem: SystemLogger } = await import('@/shared/lib/observability/system-logger');
    void SystemLogger.logWarning('Failed to load restore-log.json', { error, stage, backupName });
  }

  logData[backupName] = {
    date: new Date().toISOString(),
    logFile: `${backupName}.restore.log`,
  };

  await fs.writeFile(restoreLogPath, JSON.stringify(logData, null, 2));

  return NextResponse.json({
    message: 'Backup restored',
    log: logContent,
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type {
  CollectionSchema,
  FieldInfo,
  SchemaProvider,
  SchemaResponse,
} from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import {
  normalizeOptionalQueryString,
  optionalBooleanQuerySchema,
} from '@/shared/lib/api/query-schema';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import {
  assertDatabaseEngineManageAccessOrAiPathsInternal,
  isCollectionAllowed,
} from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const MONGO_SCHEMA_CONCURRENCY = 8;

export const querySchema = z.object({
  provider: z.preprocess(
    (value: unknown) => normalizeOptionalQueryString(value)?.toLowerCase(),
    z.enum(['auto', 'all', 'mongodb']).optional()
  ),
  includeCounts: optionalBooleanQuerySchema(),
});

const toSchemaSource = (schema: SchemaResponse): Record<string, unknown> => ({
  provider: schema.provider,
  collections: schema.collections,
  ...(schema.sources ? { sources: schema.sources } : {}),
});

async function mapWithConcurrency<T, R>(
  items: T[],
  concurrency: number,
  worker: (item: T, index: number) => Promise<R>
): Promise<R[]> {
  if (items.length === 0) return [];
  const safeConcurrency = Math.max(1, Math.min(concurrency, items.length));
  const results: Array<R | null> = Array.from({ length: items.length }, () => null);
  let nextIndex = 0;

  const runWorker = async (): Promise<void> => {
    while (true) {
      const currentIndex = nextIndex;
      nextIndex += 1;
      if (currentIndex >= items.length) return;
      const item = items[currentIndex]!;
      results[currentIndex] = await worker(item, currentIndex);
    }
  };

  await Promise.all(Array.from({ length: safeConcurrency }, () => runWorker()));
  return results.map((value: R | null): R => {
    if (value === null) {
      throw new Error('Schema concurrency mapping produced an incomplete result.');
    }
    return value;
  });
}

async function getMongoSchema(includeCounts = false): Promise<SchemaResponse> {
  const db = await getMongoDb();
  const collectionInfos = (await db.listCollections().toArray()).filter(
    (info) => !info.name.startsWith('system.')
  );
  const collections = await mapWithConcurrency(
    collectionInfos,
    MONGO_SCHEMA_CONCURRENCY,
    async (info) => {
      const collName = info.name;
      const coll = db.collection(collName);
      const sample = await coll.find({}).limit(10).toArray();

      const fieldTypes = new Map<string, Set<string>>();

      for (const doc of sample) {
        for (const [key, value] of Object.entries(doc)) {
          if (!fieldTypes.has(key)) {
            fieldTypes.set(key, new Set());
          }
          const typeSet = fieldTypes.get(key)!;
          if (value === null) {
            typeSet.add('null');
          } else if (Array.isArray(value)) {
            typeSet.add('array');
          } else if (value instanceof Date) {
            typeSet.add('date');
          } else if (
            typeof value === 'object' &&
            (value as { constructor?: { name?: string } })?.constructor?.name === 'ObjectId'
          ) {
            typeSet.add('ObjectId');
          } else {
            typeSet.add(typeof value);
          }
        }
      }

      const fields: FieldInfo[] = [];
      for (const [name, types] of fieldTypes) {
        const typeArray = Array.from(types);
        const fieldType =
          typeArray.length === 1 ? (typeArray[0] ?? 'unknown') : typeArray.join(' | ');
        const fieldInfo: FieldInfo = {
          name,
          type: fieldType,
        };
        if (name === '_id') {
          fieldInfo.isId = true;
        }
        fields.push(fieldInfo);
      }

      fields.sort((a: FieldInfo, b: FieldInfo) => {
        if (a.name === '_id') return -1;
        if (b.name === '_id') return 1;
        return a.name.localeCompare(b.name);
      });

      const entry: CollectionSchema = { name: collName, fields };

      if (includeCounts) {
        try {
          entry.documentCount = await coll.estimatedDocumentCount();
        } catch (error) {
          void ErrorSystem.captureException(error);

          // Best-effort count only.
        }
      }

      return entry;
    }
  );

  collections.sort((a: CollectionSchema, b: CollectionSchema) => a.name.localeCompare(b.name));
  return { provider: 'mongodb', collections };
}

const enrichCollections = (
  schema: SchemaResponse,
  provider: SchemaProvider
): Array<CollectionSchema & { provider: SchemaProvider }> => {
  const collections: CollectionSchema[] = Array.isArray(schema.collections)
    ? schema.collections
    : Object.values(schema.collections as Record<string, CollectionSchema>);

  return collections.map((collection: CollectionSchema) => ({
    ...collection,
    provider,
  }));
};

const filterCollectionsToAiPathsAllowlist = (schema: SchemaResponse): SchemaResponse => {
  const filteredCollections = schema.collections.filter((collection: CollectionSchema) =>
    isCollectionAllowed(collection.name)
  );

  return {
    ...schema,
    collections: filteredCollections,
  };
};

export async function getDatabasesSchemaHandler(
  request: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  const { isInternal } = await assertDatabaseEngineManageAccessOrAiPathsInternal(request);
  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const providerParam = query.provider ?? 'auto';
  const includeCounts = query.includeCounts === true;

  if (providerParam === 'all') {
    const mongoSchema = await getMongoSchema(includeCounts);
    const visibleMongoSchema = isInternal
      ? filterCollectionsToAiPathsAllowlist(mongoSchema)
      : mongoSchema;
    const payload: SchemaResponse = {
      provider: 'multi',
      collections: enrichCollections(visibleMongoSchema, 'mongodb'),
      sources: {
        mongodb: toSchemaSource(visibleMongoSchema),
      },
    };
    return NextResponse.json(payload);
  }

  const schema = await getMongoSchema(includeCounts);
  const visibleSchema = isInternal ? filterCollectionsToAiPathsAllowlist(schema) : schema;
  return NextResponse.json(visibleSchema);
}

