  const raw = Number.parseInt(process.env['DATABASE_ENGINE_BACKUP_JOB_TIMEOUT_MS'] ?? '', 10);
  if (!Number.isFinite(raw)) return 30 * 60 * 1000;
  return Math.max(5 * 60 * 1000, raw);
